    text: safeText(chunk?.text, safeText(chunk?.narration_text)),
    sentence_count: asInt(chunk?.sentence_count, 1, 1, 10),
    voice: safeText(item?.voice_url, safeText(item?.voice)),
    duration: durationSeconds,
  };
}

function pickBinaryEntry(item, normalized) {
  const binaryMap = item.binary ?? {};
  const keys = Object.keys(binaryMap);
  if (keys.length === 0) return null;

  const preferredKey = safeText(normalized.voice_binary_key);
  if (preferredKey && binaryMap[preferredKey]) {
    return [preferredKey, binaryMap[preferredKey]];
  }

  const audioKey = keys.find((key) => String(binaryMap[key]?.mimeType ?? '').toLowerCase().startsWith('audio/'));
  if (audioKey) {
    return [audioKey, binaryMap[audioKey]];
  }

  return [keys[0], binaryMap[keys[0]]];
}

const sortedEntries = inputItems
  .map((item) => ({ item, normalized: normalizeItem(item.json ?? {}) }))
  .sort((a, b) => a.normalized.order - b.normalized.order || a.normalized.scene_id.localeCompare(b.normalized.scene_id));

const aggregatedBinary = {};
const normalizedItems = sortedEntries.map((entry, index) => {
  const output = { ...entry.normalized };
  const binaryEntry = pickBinaryEntry(entry.item, output);

  if (binaryEntry) {
    const [, file] = binaryEntry;
    const targetKey = 'voice_' + String(index + 1).padStart(3, '0');
    aggregatedBinary[targetKey] = cloneBinary(file);
    output.voice_binary_key = targetKey;
    output.voice_url = 'binary:' + targetKey;
    output.voice = 'binary:' + targetKey;
    output.voice_file_name = safeText(file?.fileName, output.voice_file_name);
    output.voice_mime_type = safeText(file?.mimeType, output.voice_mime_type || 'audio/wav');
    output.voice_bytes = asInt(file?.bytes, output.voice_bytes, 0, 1000000000);
  }

  return output;
});

const first = jsonItems[0] ?? {};
const requestId = safeText(first.request_id, 'req-' + Date.now().toString(36));
const generatedCount = normalizedItems.filter((item) => item.tts_status === 'generated').length;
const failedCount = normalizedItems.filter((item) => item.tts_status === 'failed').length;
const incompleteCount = normalizedItems.filter((item) => !['generated', 'failed'].includes(item.tts_status)).length;

let status = 'success';
let errorReason = null;

if (normalizedItems.length === 0) {
  status = 'failed';
  errorReason = 'empty_items';
} else if (failedCount > 0 || incompleteCount > 0) {
  status = generatedCount > 0 ? 'partial_failed' : 'failed';
  errorReason = failedCount > 0 ? 'partial_failures' : 'unfinished_items';
}

const output = {
  json: {
    ...first,
    workflow: 'tts',
    request_id: requestId,
    status,
    media_should_run: normalizedItems.length > 0,
    media_tts_items: normalizedItems,
    items: normalizedItems,
    error_reason: errorReason,
  },
};

if (Object.keys(aggregatedBinary).length > 0) {
  output.binary = aggregatedBinary;
}

return [output];
